<script>
import set from '@/utils/base/ssh_set'
import store from '../utils/base/store'
import ssh from "./set/ssh.vue"
import git from "./set/git.vue"
import git_group from "./set/git_group.vue"
import supervisor from "./set/supervisor.vue"
import redis from "./set/redis.vue"
export default {
  props : {
    shellShowResult : {
      type : String
    },
  },
  components: {
    ssh,
    git,
    git_group,
    supervisor,
    redis,
  },
  data() {
    return {
      name: 'Ssh',
      sshList : [],
      //ssh config
      sshConfig: {
        username: '',
        password: '',
        host: '121.40.109.241',
        port: '22',
      },
      //wk ssh config
      wkSshConfig: {
        username: '',
        password: '',
        host: '47.99.70.6',
        port: '22',
      },
      //数据库
      devDbConfig: {
        host: '',
        port: 3306,
        username: '',
        password: '',
        dbname: '',
      },
      //prod ssh config
      prodTestSshConfig: {
        username: '',
        password: '',
        host: '47.96.139.231',
        port: '22',
      },
    }
  },
  mounted: function () {
    if (process.env.NODE_ENV === 'production') {
      this.apiHost = ''
    }
    let sshConfig = this.getStore('sshConfig')
    if (sshConfig !== null) {
      this.sshConfig = JSON.parse(sshConfig)
    }

    let wkSshConfig = this.getStore('wkSshConfig')
    if (wkSshConfig !== null) {
      this.wkSshConfig = JSON.parse(wkSshConfig)
    }

    let prodTestSshConfig = this.getStore('prodTestSshConfig')
    if (prodTestSshConfig !== null) {
      this.prodTestSshConfig = JSON.parse(prodTestSshConfig)
    }

    let devDbConfig = this.getStore('devTestDbConfig')
    if (devDbConfig !== null) {
      this.devDbConfig = JSON.parse(devDbConfig)
    }
    this.SshList()
  },
  methods: {
    handleTabClick : function (tab){
      let index = tab.index
      switch (index){
        case '0':
          this.$refs.ssh.SshList();
          break
        case '1':
          this.$refs.git_group.GitGroupList()
          break
        case '2':
          this.$refs.git.GitList()
          this.$refs.git.GitGroupList()
          this.$refs.git.SshList()
          break
      }
    },
    SshList : function (){
      let _that = this
      set.SshList(function (response){
        console.log(response)
        if(response.ErrCode === 0){
          _that.sshList = response.Data
        }
      })
    },
    //保存ssh配置
    saveSshConfig: function (prefix) {
      if (prefix === 'prodTest') {
        if (this.prodTestSshConfig.username === '') {
          this.error('用户名不能为空')
          return
        } else if (this.prodTestSshConfig.password === '') {
          this.error('密码不能为空')
          return
        } else if (this.prodTestSshConfig.host === '') {
          this.error('连接IP不能为空')
          return
        } else if (this.prodTestSshConfig.port === '') {
          this.error('端口不能为空')
          return
        }
        this.setStore(
          'prodTestSshConfig',
          JSON.stringify(this.prodTestSshConfig)
        )
        store.removeStore('Unikey')
        window.location.reload();
        this.success('设置成功')
      } else if (prefix === 'dev') {
        if (this.sshConfig.username === '') {
          this.error('用户名不能为空')
          return
        } else if (this.sshConfig.password === '') {
          this.error('密码不能为空')
          return
        } else if (this.sshConfig.host === '') {
          this.error('连接IP不能为空')
          return
        } else if (this.sshConfig.port === '') {
          this.error('端口不能为空')
          return
        }
        this.setStore('sshConfig', JSON.stringify(this.sshConfig))
        store.removeStore('Unikey')
        window.location.reload();
        this.success('设置成功')
      } else if (prefix === 'wk_dev') {
        if (this.wkSshConfig.username === '') {
          this.error('用户名不能为空')
          return
        } else if (this.wkSshConfig.password === '') {
          this.error('密码不能为空')
          return
        } else if (this.wkSshConfig.host === '') {
          this.error('连接IP不能为空')
          return
        } else if (this.wkSshConfig.port === '') {
          this.error('端口不能为空')
          return
        }
        this.setStore('wkSshConfig', JSON.stringify(this.wkSshConfig))
        store.removeStore('Unikey')
        window.location.reload();
        this.success('设置成功')
      }
    },
    saveDbConfig: function () {
      if (this.devDbConfig.host === '') {
        this.error('host不能为空')
        return
      } else if (this.devDbConfig.password === '') {
        this.error('password不能为空')
        return
      } else if (this.devDbConfig.username === '') {
        this.error('username不能为空')
        return
      } else if (this.devDbConfig.password === '') {
        this.error('password不能为空')
        return
      } else if (this.devDbConfig.dbname === '') {
        this.error('dbname不能为空')
        return
      }
      this.setStore('devTestDbConfig', JSON.stringify(this.devDbConfig))
      store.removeStore('Unikey')
      this.success('设置成功')
    },
    success: function (msg) {
      // Message.success(msg);
      this.$notify({
        title: '提示',
        message: msg,
        type: 'success',
        duration: 1000,
      })
    },
    warning: function (msg) {
      // Message.warning(msg);
      this.$notify({
        title: '提示',
        message: msg,
        type: 'warning',
        duration: 1000,
      })
    },
    info: function (msg) {
      // Message.info(msg);
      //this.$notify({title: '提示', message: msg});
      this.$notify({
        title: '提示',
        message: msg,
        type: 'info',
        duration: 1000,
      })
    },
    error: function (msg) {
      // Message.error(msg);
      this.$notify({
        title: '提示',
        message: msg,
        type: 'error',
        duration: 1000,
      })
    },
    setStore: function (key, value) {
      localStorage.setItem(key, value)
    },
    getStore: function (key) {
      return localStorage.getItem(key)
    },
  },
}
</script>

